  ('aboriginal-6e11b43e-moex-00102', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政組織之敘述，下列何者錯誤？', '["國家中山科學研究院為國防部所屬之行政機關", "中央選舉委員會為合議制之行政機關", "國家通訊傳播委員會為獨立機關", "我國之公立大學雖具大學自治權，但非獨立之公法人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00103', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於公營造物之敘述，下列何者錯誤？', '["係行政主體為特定目的而設置", "公營事業中依民法或公司法設立之法人，屬公營造物概念", "功能上結合人與物，形成公營造物利用關係", "監獄為公法關係之營造物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00104', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '中華民國國民取得外國國籍者，若依相關規定取得主管機關核准，得擔任下列何職位？', '["中央研究院研究員", "臺灣中油公司之總經理", "僑務主管機關之有給職委員", "經濟部產業發展署專門委員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00105', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於公務人員權益保障之敘述，下列何者正確？', '["公務人員因涉嫌犯罪，而遭停職，其停職期間已不具公務人員身分", "公務人員對於長官監督範圍內所發之口頭命令，認為有違法時，應服從而不得請求長官以書面 署名為命令", "公務人員保障暨培訓委員會處理保障事件時，即使涉及公務人員所屬機關權限之行使，仍得依 職權進行案件之調處", "公務人員不服服務機關之管理措施時，得向公務人員保障暨培訓委員會提起申訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00106', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於公務員懲戒法之敘述，下列何者錯誤？', '["懲戒權之行使，由懲戒法院為之", "受懲戒之對象，限於現職公務員", "公務員之違法失職行為，非因故意或過失不予懲戒", "逾越懲戒處分行使期間，應為免議之判決 40950"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00107', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於法規命令之敘述，下列何者正確？', '["法規命令之擬訂與發布，原則上均應刊載於政府公報或新聞紙", "法規命令乃行政機關直接依據法律明確授權而訂定，故立法院對法規命令並無任何審查權力", "法規命令之訂定，人民或團體不得提議並草擬之", "行政機關訂定法規命令，均應舉行聽證"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00108', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於地方自治法規之敘述，下列何者正確？', '["直轄市政府為辦理中央機關委辦事項，得依其法定職權訂定委辦規則", "直轄市自治規則應於發布後函報中央各該主管機關備查", "地方行政機關得訂定自律規則", "直轄市政府所屬機關及學校之組織規程，由直轄市議會定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00109', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '甲為 A 地所有權人，乙機關為需用土地機關，在徵收 A 地以作為學校預定地後，依司法實務見 解，下列敘述何者正確？', '["國家應待甲提出申請後，再作成徵收補償處分", "土地徵收決定本身性質上為行政處分，而原處分機關則是核准徵收之機關，非需用土地機關", "甲認為徵收補償費之價額過低時，應提起撤銷訴訟加以救濟", "若逾期未發給徵收補償費時，該徵收土地核准案並未從此失其效力，而是屬於違法得撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00110', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依司法實務見解，下列何者非屬行政處分？', '["私立大學教師收到學校之停聘通知書", "公務人員之年終考核列乙等", "汽車燃料使用費通知書", "役男體位判定通知書"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00111', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-113-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', 'A市政府都市發展局（下稱都發局）認為B公司於甲地上經營夜市，違反都市計畫法相關規定， 遂裁處B公司新臺幣6萬元罰鍰。下列敘述何者正確？', '["該處分作成前，原則上應給予B公司陳述意見之機會", "若該處分合法，則都發局即不得依職權為全部或一部之廢止", "該處分以書面作成時，若無法在該處分中得知都發局為處分機關時，該處分屬違法得撤銷", "針對該處分之救濟方法、期間及受理機關，並非屬於書面處分應記載之事項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:11+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "405", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL)
